module RefModule(
	input clk,
	input reset,
	input enable,
	output reg [9:0] count);  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge reset or posedge dbg_halt) begin
		if (reset)
			count <= 10'b0000000000;
		else if (enable)
			count <= count + 1;
	end

endmodule
